var e=JSON.parse(`[{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……어어?","JPN":"……あれ？","ENG":"...Err?","TWN":"……嗯？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"여긴 어디지?","JPN":"ここはどこ？","ENG":"Where am I?","TWN":"這裡是哪裡？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아아, 어떡해…….","JPN":"ああ、どうしよう……","ENG":"Oh, no...","TWN":"哎呀，怎麼辦……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"또 나도 모르게 배에 올라탔나 봐.","JPN":"また無意識に船に乗っちゃったみたい。","ENG":"I got on the ship in spite of myself, again.","TWN":"我好像又不自覺地搭上船了？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아이 참. 분명, 피오네 언니를 따라가고 있었는데…… 왜 또 배에 타게 된 거지?","JPN":"確かにフィオネさんについて行ってたはずだけど……なんでまた船に乗っちゃったんだろ？","ENG":"Ugh, I was following Fione. How did I get on this ship?","TWN":"真是的，我明明就跟著菲奧尼姊姊……為什麼又搭上船了呢？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……그래, 침착하자.","JPN":"……うん。落ち着いて行動しよう。","ENG":"...No. Stay calm, Arius.","TWN":"……好，冷靜點。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저번처럼 피오네 언니한테 전화만 걸면, 다시 돌아갈 수 있어.","JPN":"この前みたいにフィオネさんに電話さえしたら、また戻れる。","ENG":"If you can call Fione like the last time, you can go back.","TWN":"就跟像上次一樣，只要打電話給菲奧尼姊姊，就可以回去了。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……그때 화물선에서 돌아왔던 것처럼!","JPN":"……貨物船から戻ってきた時みたいに！","ENG":"Just like from the freight ship the last time!","TWN":"……就跟搭上貨船那次一樣！"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……그런데 생각해보니까.","JPN":"……でも、そういえば。","ENG":"...Wait. But now that I think of it,","TWN":"……不過…仔細想想。"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그때도 피오네 언니한테 많이 혼났었는데…….","JPN":"あ、あの時もフィオネさんにすごく怒られたけど……","ENG":"F-Fione was really upset last time.","TWN":"那…那時候好像也有被菲奧尼姊姊臭罵一頓……"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이번에도 많이 혼나겠지……?","JPN":"今回も怒られるだろうなあ……","ENG":"She'll be upset again... won't she?","TWN":"這次應該也會被罵臭頭吧……？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……어떡해.","JPN":"……どうしよう。","ENG":"...What do I do?","TWN":"……怎麼辦？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_DARK_QM","text":{"KOREA":"……길을 잃으신 분인가 보군요.","JPN":"……道に迷っていらっしゃるようですね。","ENG":"You look like you don't know where you are.","TWN":"……你迷路了嗎？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L25_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……えっ？","ENG":"...Pardon?","TWN":"……嗯？"},"stage":{"bg":"CRUISE","bgm":"THEMA_SUMMER_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경!!","JPN":"アリウス卿！！","ENG":"Dame Arius!","TWN":"埃里奧斯卿！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"제가 얼마나 걱정한 줄 아세요?","JPN":"どれだけ心配したかわかりますか！？","ENG":"I was worried sick about you!","TWN":"你知道我有多擔心你嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐 한 눈을 판 사이에 또 어딜 가신 겁니까?","JPN":"少し目を離した間に、どこに行かれたんですか？","ENG":"Where did you go again while I was looking away for a moment?","TWN":"我才一個不留神，你又跑哪裡去了？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"평소에는 그렇게 얌전하신 분이 왜 밖에만 나갔다 하면 없어지는 겁니까!","JPN":"普段はあれだけ大人しくしているに、なぜ外に出るたびにいなくなるんですか！","ENG":"How come you always disappear whenever you're outside, even though you're usually such a good girl?","TWN":"平時那麼乖巧，為什麼一到外面就會不見人影呢？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"옛말에 물가에 내놓은 아이라는 말이 있는데, 에리어스 경이 딱 그렇군요.","JPN":"本当にアリウス卿は油断もならないですね。","ENG":"You're like a toddler left alone by the poolside.","TWN":"人家說出去像走丟，回來像撿到，說的就是你吧！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"참고로 저희 팔촌께서도 한 번 길을 잃은 적이……","JPN":"ちなみに私の遠い親戚も道に迷ったことがあって……","ENG":"To tell you the truth, my second cousin twice removed also got lost once—","TWN":"提供參考，我們整個家族都沒人迷路過……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"죄송해요! 피오네 언니!","JPN":"ごめんなさい、フィオネさん！","ENG":"I'm so sorry, Fione!","TWN":"對不起！菲奧尼姊姊！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그래요, 그래서 지금 어디입니까?","JPN":"それで、今どちらですか？","ENG":"Okay, so where are you now?","TWN":"好啦，所以你現在人在哪裡？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"제가 즉시 그쪽으로 갈 테니 꼼짝 말고 계시죠.","JPN":"今すぐそちらに向かいますので。","ENG":"I'll be there soon. You stay put.","TWN":"我馬上過去找你，你千萬不要亂跑。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저, 그게…….","JPN":"あの、それが……","ENG":"Erm, that's...","TWN":"那個……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"에리어스의 언니 분이로군요. 에리어스 양은 저희가 맡고 있답니다.","JPN":"アリウスさんのご家族の方でしょうか。アリウスさんは私たちが保護しています。","ENG":"You must be Arius's guardian. Right now, she's with us.","TWN":"是埃里奧斯的姊姊嗎？埃里奧斯現在有我們照顧她。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아, 에리어스 경을 보호하고 계신 분이군요.","JPN":"あ、アリウス卿を保護してくださっているんですね。","ENG":"Oh, you're with Dame Arius.","TWN":"是保護埃里奧斯卿的人嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"감사합니다. 이 은혜를 어떻게 갚아야 할지……","JPN":"ありがとうございます。この恩をどう返せば……","ENG":"Thank you. I don't know how I can repay you...","TWN":"謝謝你，你的大恩大德……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"위치만 알려주시면 제가 즉시 그쪽으로 가겠습니다.","JPN":"場所を教えてくださったら、今すぐ向かいます。","ENG":"Please tell me where you are. I'll be there right away.","TWN":"請告訴我你們的位置，我馬上過去。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건 곤란하겠군요. 여기는 바다 위라서요.","JPN":"それは難しいですね。こちらは海の上でして。","ENG":"I'm sorry, but you can't. We're in the middle of the sea.","TWN":"可能有點困難，我們現在在海上。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"바다……!?","JPN":"海……！？","ENG":"The sea…!?","TWN":"海上……？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경…… 설마 또!?","JPN":"アリウス卿……まさか、また……！？","ENG":"Dame Arius, did you...? No!","TWN":"埃里奧斯卿……你該不會又？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"대신 이 배의 목적지를 알려드리도록 하죠. 거기서 합류하는 건 어떨까요?","JPN":"その代わり、この船の目的地をお教えします。そこで合流するのはどうでしょう。","ENG":"But I can tell you where this ship is heading. Why don't you meet us there?","TWN":"不過我可以告訴你這艘船的目的地，我們直接在那會合好嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……네, 알겠습니다. 그렇게 하시죠.","JPN":"……はい、わかりました。そうしましょう。","ENG":"...Yes, let's do that.","TWN":"……好，沒問題，就這麼辦吧。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경, 무슨 일이 있었는지 이번에는……","JPN":"アリウス卿、何があったのか今度こそ……","ENG":"Dame Arius, I don't know what happened, but this time—","TWN":"埃里奧斯卿，這次是發生什麼事……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L8_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……통신이 끊어졌군요.","JPN":"……通信が途切れてしまいましたね。","ENG":"We got disconnected.","TWN":"……訊號斷了。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"불길한 바람이네요.","JPN":"不吉な風です。","ENG":"This wind is ominous.","TWN":"是不吉利的風兆呢。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"이야~ 다들 안녕하신가?","JPN":"いや～皆さん元気ですか？","ENG":"Hello! How are you, guys?","TWN":"嗨～大家好～"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_BOOM"},{"id":"L13_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"아, 우리 안부는 물을 필요 없어! 이제부터 불행 끝, 안녕 시작이거든!","JPN":"あ、答える必要はないよ。こっちは不幸が終わり、幸せが訪れる予定なんだ。","ENG":"Ah, no need to ask after us. Our lives are about to change—for the better!","TWN":"喔～不需要跟我們問好！因為我們的不幸很快就會結束，要開始過好日子囉！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"배때지에 기름 잔뜩 낀 부자 놈들, 행복한 여객선 여행은 여기서 끝이야!","JPN":"肥えに肥えた金持ちどもめ。ハッピークルーズ旅行はここで終わりだ！","ENG":"You filthy, rich pigs. Your happy, luxurious cruise trip ends here and now!","TWN":"你們這些荷包滿滿的有錢人，幸福的遊輪之旅結束囉！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"하하하, 다들 바닥에 꿀 발라 놓은 것 마냥 납작 엎드리라고.","JPN":"ははは、みんな大人しく床にひれ伏しな。","ENG":"Hah hah hah! Everyone, stay flat on the floor and don't even raise your head!","TWN":"哈哈，全都給我趴在地上別動！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"이봐, 삼류 악당처럼 웃지만 말고 돈 될 만한 거 보이면 몽땅 챙겨!","JPN":"おい、三流の悪党みたいに笑ってないで、金になりそうなものは全部入れろ！","ENG":"Hey, stop laughing like a third-rate villain and start grabbing expensive-looking things!","TWN":"喂，不要像三流的反派一樣笑得那麼噁心，看到值錢的東西就全部拿走！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM_03"},{"id":"L20_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……물러서십시오, 당주님. 제가 처리하겠습니다.","JPN":"……お下がりください、当主。私が処理します。","ENG":"...Please step back, my lady. Let me take care of them.","TWN":"……堂主，您先走，他們交給我來處理。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"치후유, 섣불리 움직이면 무고한 사람들이 다칠 수도 있습니다.","JPN":"千冬、迂闊に行動したら罪のない人々が怪我するかもしれません。","ENG":"Chifuyu, let's not make a rash move. We don't want to hurt the innocent.","TWN":"千冬，輕舉妄動怕會傷到無辜的人。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"잠시 사태를 지켜보면서…… ","JPN":"少し様子を見て…… ","ENG":"For now, let's watch the situation— ","TWN":"先看看情況……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L23_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"응?","JPN":"あれっ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"에리어스 양이 어디로 갔죠?","JPN":"アリウスさんはどちらに？","ENG":"Where did Arius go?","TWN":"埃里奧斯呢？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……단장님이 말씀하셨어요.","JPN":"……団長が言ってました。","ENG":"...The Captain said it.","TWN":"……團長說過。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"조디악 나이츠는 민중을 지키는 기사단이라고.","JPN":"ゾディアックナイツは、民衆を守る騎士団だと。","ENG":"We, the Zodiac Knights, serve the public.","TWN":"十二宮騎士團是守護民眾的騎士團。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그러니까.","JPN":"だ、だから。","ENG":"S-so...","TWN":"所…所以。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저도 조디악 나이츠의 일원이니까…….","JPN":"私もゾディアックナイツの一員ですから……","ENG":"As a Zodiac Knight,","TWN":"我也是十二宮騎士團的一員……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"이런 일을 못 본 척 해서는 안 돼요.","JPN":"こんなこと、見過ごすわけにはいきません。","ENG":"I must not stand aside in a situation like this.","TWN":"不能假裝沒看到。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"엉? 넌 또 뭐야, 꼬맹이. 여기 든 이거, 이거 장난감이 아니야.","JPN":"あ？　なんだこのガキは。これはおもちゃじゃないんだぞ。","ENG":"Err? What, girl? See this here? This isn't a toy.","TWN":"嗯？你是誰啊，小不點？有看到我手裡拿的這個嗎？這可不是玩具喔！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"꼬마야, 좋은 말 할 때 얌전히 숨어 있는 게 좋을 꺼야.","JPN":"ガキ、痛い目にあう前に、大人しく隠れてろ。","ENG":"Girl, go stay in a corner when I ask nicely.","TWN":"小不點，趁我還沒發脾氣前，你最好乖乖躲起來。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"우린 아동, 청소년 심의 규정을 준수하는 착한 해적이거든.","JPN":"俺たちはこども基本法と少年法を守る優しい海賊だからな。","ENG":"We may be pirates, but we believe the children are our future.","TWN":"我們可是遵守兒少法的善良海盜。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"그래서 어린이를 다치게 하는 건 싫어.","JPN":"ガキを怪我させたくはねえんだ。","ENG":"We don't like hurting children. Do you hear me?","TWN":"所以不想傷害小孩子。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"그, 그래도 자꾸 다가오면 어쩔 수 없다고?","JPN":"で、でもあまりにも近づいてきたら容赦はしねえぞ？","ENG":"B-but I'll hurt you if I have to.","TWN":"但…你再繼續靠近的話，就別怪我們囉？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L47_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"어이, 꼬마야? 한 번 해보자는 거야?","JPN":"おい、ガキ。一丁やるか？","ENG":"Hey, girl. Want to fight or what?","TWN":"喂，小不點？你是想打架嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"망토 같은 걸 걸친 거 보면 혹시 카운터인가 뭔가 하는 그거니?","JPN":"そのマント、もしかしてカウンターとか何とかっつーあれか？","ENG":"You're wearing a cape. Are you a Counter or something?","TWN":"看你披著像是披風的東西，該不會是什麼制裁者吧？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……여, 여러분.","JPN":"……み、皆さん。","ENG":"…E-everyone.","TWN":"……各…各位。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"……꿀꺽.","JPN":"……ごくり。","ENG":"...*Gulp!*","TWN":"……咕嚕。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"포, 폭력은 나쁜 거예요. 다른 사람의 물건을 뺏는 것도 나쁜 거고요.","JPN":"ぼ、暴力は悪いことです。人の物を奪うことも悪いことです。","ENG":"P-please don't resort to violence! Don't steal from other people, either.","TWN":"暴…暴力是不好的，搶別人的東西也是不好的。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……그러니까 이제 그만두셨으면 좋겠어요.","JPN":"……だから、やめて欲しいんです。","ENG":"So... please stop.","TWN":"……所以請你們住手。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"……응?","JPN":"……ん？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"세상에 누가 그런다고 그만두냐?","JPN":"やめて欲しいって言われてやめるやつがいると思うか？","ENG":"No one's going to stop because you said so.","TWN":"好笑，有人會就這樣乖乖住手嗎？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"그만 둘래.","JPN":"やめる。","ENG":"I want to stop.","TWN":"我要收手了！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"……엥? 너 무슨 소리야.","JPN":"……はあ？　何言ってんだお前。","ENG":"...Say what? What the hell are you talking about?","TWN":"……啥？你在胡說什麼！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"저렇게 활짝 웃는 애한테 어떻게 총부리를 겨눌 수 있어?","JPN":"あんな笑顔のガキに銃なんて向けられねえよ。","ENG":"Look at her. Can you really point your gun at a smiling girl like that?","TWN":"怎麼能把槍口對著那麼天真可愛的孩子呢？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"액션 영화에서도 개랑 어린이한테 총 쏘는 건 <color=#ffd34c>금기 사항</color>이라고.","JPN":"アクション映画でも犬と子どもを撃つのは<color=#ffd34c>禁忌</color>なんだ。","ENG":"Shooting dogs and children is <color=#ffd34c>taboo</color> even in action movies.","TWN":"聽說就算是動作電影，也是<color=#ffd34c>禁止</color>對狗狗和兒童開槍的。"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"아, 아니…… 이거랑 그게 대체 무슨 상관이야!","JPN":"い、いや……それとこれは関係ねえだろ！","ENG":"Wh-what the...? What does it have anything to do with this?","TWN":"不…不是……這和那個有什麼關係！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"이봐, 다시 한 번…….","JPN":"おい、もっかい……","ENG":"Hey, I'm gonna—","TWN":"喂，你再想想……"},"stage":{"bg":"SUMMER_HOTEL","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_B","text":{"KOREA":"커헉……!","JPN":"がはっ……！","ENG":"Aack...!","TWN":"唔……！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIRATE_NPC_SAILOR_B","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"뭐, 뭐야?","JPN":"な、なんだ？","ENG":"W-what the hell?","TWN":"這…這是怎樣？"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PIRATE_NPC_SAILOR_A","text":{"KOREA":"여자 검사? 언제 우리 뒤를 잡은 거지?!","JPN":"女の剣士？　いつの前に後ろに！？","ENG":"A swordswoman? When did she get behind us?","TWN":"你是女俠客嗎？你是什麼時候跑到我們背後的？！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIRATE_NPC_SAILOR_A","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……그대로 손가락 하나 움직이지 말거라.","JPN":"……指一本動かすな。","ENG":"...Don't even move a finger.","TWN":"……一根手指頭也不准動！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"지금이다! 해적들을 제압해!","JPN":"今だ！　海賊どもを制圧するんだ！","ENG":"Now! Subdue the pirates!","TWN":"就是現在！拿下那些海盜！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"저항하지 마, 이 자식들!!","JPN":"抵抗するな、こら！","ENG":"Don't even think about fighting back, you jerks!","TWN":"勸你們別掙扎！"},"stage":{"bg":"SUMMER_HOTEL","bgm":"THEMA_SUMMER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……피오네 언니!","JPN":"……フィオネさん！","ENG":"...Fione!","TWN":"……菲奧尼姊姊！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"늦었군요, 에리어스 경.","JPN":"遅くなりましたね、アリウス卿。","ENG":"Sorry I'm late, Dame Arius.","TWN":"我來晚了，埃里奧斯卿。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……보고 싶었어요.","JPN":"……会いたかったです。","ENG":"...I missed you!","TWN":"……我好想你喔。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"말도 없이 또 사라져서 절 놀라게 하다니… 따끔하게 혼날 각오는 되셨죠?","JPN":"何も言わずにまた消えて、びっくりさせて……怒られる覚悟はできていますね？","ENG":"You disappeared without telling me again. Are you ready for your punishment?","TWN":"你突然就這樣消失不見，嚇死我了……你做好挨罵的心理準備了吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"헤헤, 죄송해요.","JPN":"えへへ、ごめんなさい。","ENG":"Heh heh. Sorry.","TWN":"嘿嘿，對不起。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"여기 오는 동안 무슨 일 있었습니까?","JPN":"ここに来る間に、なにかあったんですか？","ENG":"Did something happen on your way here?","TWN":"在我來的路上有發生什麼事嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"저번처럼 잔뜩 울상일 줄 알았는데…… 의외군요.","JPN":"前回みたいに泣いているんだろうと思っていましたが……意外ですね。","ENG":"You're not tearful like the last time.","TWN":"我還以為你會像上次一樣嚎啕大哭呢……真令人意外。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……헤헷, 그게요.","JPN":"……えへへ、実はですね。","ENG":"Heh heh. No.","TWN":"……嘿嘿，就是說啊。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"에리어스 양이 무사히 집에 돌아갈 수 있어서 다행이에요.","JPN":"アリウスさん、無事お家に帰ることができてよかったです。","ENG":"I'm glad Arius can go back home safely.","TWN":"埃里奧斯能平安回家真是太好了。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"아, 에리어스 경을 보호해 주신 분이군요.","JPN":"あっ、アリウス卿を保護してくだった方ですか。","ENG":"Oh, you're the one who took care of Dame Arius.","TWN":"是你們保護埃里奧斯卿的嗎？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"어떻게 감사의 말씀을 드려야 할 지……. 사례는 반드시 하겠습니다.","JPN":"どうお礼をしたらいいか……この恩は必ずお返しします。","ENG":"I can't thank you enough... I will be sure to repay this debt.","TWN":"真不知道該如何謝謝你們……我會準備一份謝禮報答二位的。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"사례를 받을 정도의 일은 아니었습니다.","JPN":"謝礼をいただくほどのことではありません。","ENG":"No need.","TWN":"舉手之勞，無需掛齒。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"오히려 에리어스 양의 용기 덕분에 다치는 사람 없이 끝낼 수 있었으니까요.","JPN":"むしろ、アリウスさんの勇気のおかげで、怪我人が出ることなく済みましたから。","ENG":"Besides, Arius's courage saved us all.","TWN":"反倒是因為埃里奧斯的勇敢，我們才能在不傷害到無辜的前提下，解決掉他們呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……네?","JPN":"……えっ？","ENG":"…Sorry?","TWN":"……嗯？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"다치는 사람이 없었다는 말은……?","JPN":"怪我人が出なかった、と言いますと……？","ENG":"What do you mean, she saved you all?","TWN":"不傷害到無辜……？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네! 엄청 무서운 해적들을 만났어요! 집에 가면 피오네 언니한테도 이야기 해드릴게요!","JPN":"すごく怖い海賊に出会ったんです！　帰ったらフィオネさんにもお話します！","ENG":"Oh, we met some scary-looking pirates. I'll tell you all about them when we go home.","TWN":"對啊！我們遇到很可怕的海盜喔！等回家之後我再說給菲奧尼姊姊聽！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……언니들 고마웠어요. 제가 도움이 되었다니 기뻐요.","JPN":"……皆さん、ありがとうございました。私が役に立てて嬉しいです。","ENG":"Thank you, Chifuyu, Chinatsu. I'm glad I could be of help.","TWN":"……謝謝兩位姊姊，很開心能幫上忙。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"에리어스 양은 용기와 함께 겸양의 미덕까지 갖추신 분이군요.","JPN":"アリウスさんは勇気だけでなく、謙遜の美徳も備えているのですね。","ENG":"Arius, you're courageous and polite.","TWN":"埃里奧斯不只勇敢，還兼具謙卑的美德呢。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이건 두 분께 드리는 약소한 선물입니다.","JPN":"ささやかですが、お二人へのプレゼントです。","ENG":"This is our small gift for you two.","TWN":"這是送你們的一點小小心意。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이곳에서 유명한 <color=#ffd34c>온천여관 숙박권</color>이에요.","JPN":"この近くで有名な<color=#ffd34c>温泉の宿泊券</color>です。","ENG":"A <color=#ffd34c>voucher</color> for a famous hot spring inn in this place.","TWN":"是這裡知名<color=#ffd34c>溫泉旅館的住宿券</color>。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"우리의 인연이 좋은 추억으로 남길 바라는 뜻에서 드리는 것이니 부디, 사양 마시길.","JPN":"今日の出会いがよき思い出になってほしいという気持ちで贈るものですから、どうぞご遠慮なく。","ENG":"Please accept it. We'd like to commemorate our new friendship.","TWN":"請務必要收下，希望這次的相遇能留下美好的回憶。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"……이, 이건?","JPN":"……こ、これは？","ENG":"Th-this...","TWN":"……這…這個是？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"이, 이게 약소하다고요? 이건 최상급 여관의…….","JPN":"こ、これがささやかですって……？　これは最高級旅館の……","ENG":"This isn't a small gift. This place is the best in town.","TWN":"這…這叫小小心意？這是頂級旅館的……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"우와, 온천이요? 재밌겠다!","JPN":"わあ、温泉ですか？　楽しそう！","ENG":"Whoa, a hot spring? I'd love to!","TWN":"哇，溫泉嗎？感覺好好玩！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"온천은 한 번도 가본 적 없거든요. 감사합니다.","JPN":"温泉には一度も行ったことがないんです。ありがとうございます。","ENG":"I've never been to a hot spring. Thank you.","TWN":"我還沒去過溫泉呢，謝謝姊姊！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……아!","JPN":"……あ！","ENG":"...Ah!","TWN":"……哎呀！"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그치만 피오네 언니는 쉬는 걸 별로 안 좋아 하실 것 같은데……. ","JPN":"で、でもフィオネさんは、休むのはあまり好きじゃないんじゃ…… ","ENG":"B-but Fione doesn't like lazing around... ","TWN":"可是…菲奧尼姊姊好像不怎麼喜歡休假欸……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"흠흠! 에리어스 경.","JPN":"ごほん！　アリウス卿。","ENG":"Ahem, ahem! Dame Arius.","TWN":"咳咳！埃里奧斯卿。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"여객선에 탔다가 무서운 해적을 만났다고 했죠?","JPN":"クルーズ船に乗って、怖い海賊に出会ったと言いましたね。","ENG":"You said you met some scary-looking pirates while on the cruise, yes?","TWN":"你說在船上遇到很可怕的海盜是吧？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네?","JPN":"えっ？","ENG":"Yes...?","TWN":"什麼？"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"가시죠. 용감한 기사의 모험담은 여관에서 듣도록 하겠습니다.","JPN":"行きましょう。勇敢な騎士の冒険譚は、旅館で聞かせてもらいますから。","ENG":"Let's go. You can tell me all about it at the inn.","TWN":"走吧。我就在旅館裡，聽你說勇敢的騎士冒險故事吧。"},"stage":{"bg":"SUMMER_BEACH_NIGHT","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};